section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/ai-prompt-patterns-test-ideation.json",
  "title": "AI Prompt Patterns for Test Ideation",
  "type": "object",
  "required": [
    "artefact_id",
    "function_id",
    "patterns_used",
    "boundary_cases",
    "oracles",
    "mutations_caught",
    "coverage_target",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "function_id": {
      "type": "string",
      "description": "module.function the tests target",
      "minLength": 1
    },
    "patterns_used": {
      "type": "array",
      "description": "subset of [boundary, oracle, mutation]",
      "minItems": 1
    },
    "boundary_cases": {
      "type": "array",
      "description": "list of edge inputs and expected behaviour",
      "minItems": 1
    },
    "oracles": {
      "type": "array",
      "description": "list of {property, violating_test}",
      "minItems": 1
    },
    "mutations_caught": {
      "type": "array",
      "description": "list of {mutation_description, test_id_that_catches}",
      "minItems": 1
    },
    "coverage_target": {
      "type": "number",
      "description": "branch coverage threshold, conventionally 0.8"
    }
  },
  "additionalProperties": false
}
